    int secondaryDiagonalSum = 0;
    for (int i = 0; i < 3; ++i) {
        secondaryDiagonalSum += matrix[i][2 - i];
    }

    // 输出结果
    cout << mainDiagonalSum << " " << secondaryDiagonalSum << endl;

    return 0;
}
