/* 文件头注释：使用宏定义实现变量交换 */
#include <bits/stdc++.h>
using namespace std;

// 定义带参的宏，用于交换两个变量的值
#define SWAP(a, b) { int temp = a; a = b; b = temp; }

int main() {
    int num1, num2;
    // 输入两个数
    cin >> num1 >> num2;
    // 使用宏交换两个数的值
    SWAP(num1, num2);
    // 输出交换后的结果
    cout << num1 << " " << num2 << endl;
    return 0;
}
```

### 代码说明：
1. `#define SWAP(a, b) { int temp = a; a = b; b = temp; }`：定义一个宏`SWAP`，用于交换两个变量的值。宏中使用了一个临时变量`temp`来辅助交换。
2. `cin >> num1 >> num2;`：从标准输入读取两个整数。
3. `SWAP(num1, num2);`：调用宏`SWAP`交换`num1`和`num2`的值。
4. `cout << num1 << " " << num2 << endl;`：输出交换后的两个数。

### 注意事项：
