/* 文件头注释：使用二分查找和数学推导确定最右侧灯的最低高度 */
#include <bits/stdc++.h>
using namespace std;

const double EPS = 1e-9; // 精度控制

// 计算给定B时，所有灯的高度是否都不低于地面
bool isValid(int N, double A, double B) {
    vector<double> H(N);
    H[0] = A;
    H[1] = B;
    for (int i = 2; i < N; ++i) {
        H[i] = 2 * (H[i-1] + 1) - H[i-2];
        if (H[i] < 0) return false;
    }
    return true;
}

int main() {
    int N;
    double A;
    cin >> N >> A;

    double left = 0, right = A; // B的范围在0到A之间
    while (right - left > EPS) {
        double mid = (left + right) / 2;
        if (isValid(N, A, mid)) {
            right = mid;
        } else {
            left = mid;
        }
    }

    cout << fixed << setprecision(2) << right << endl;
    return 0;
}
```

### 代码说明：
1. `isValid`函数用于检查给定B时，所有灯的高度是否都不低于地面。通过递推公式计算每个灯的高度，并检查是否有灯的高度为负数。
2. `main`函数中，使用二分查找在0到A之间寻找最小的B，使得所有灯的高度都不低于地面。
3. 输出结果精确到小数点后两位。

